export interface SocialProfile {
  name: string;
  handle: string;
  platform: 'LinkedIn' | 'X' | 'Instagram' | 'GitHub' | 'YouTube' | 'TikTok' | 'Medium' | 'Other';
  bio: string;
  relevanceScore: number;
  url: string;
  tags: string[];
}

export interface ProfileAnalysis {
  originalProfile: {
    name: string;
    niche: string;
    description: string;
  };
  suggestions: SocialProfile[];
  groundingSources: Array<{
    title: string;
    uri: string;
  }>;
}

export interface SearchState {
  loading: boolean;
  error: string | null;
  results: ProfileAnalysis | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProfileAnalysis } from "../types";

export class GeminiService {
  private static ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  static async analyzeAndSearch(profileUrl: string): Promise<ProfileAnalysis> {
    const prompt = `
      Analyze this social media profile URL: ${profileUrl}.
      First, identify who this person/brand is and what their main niche or industry is.
      Then, search for 6 highly relevant similar profiles across platforms like X (formerly Twitter), LinkedIn, Instagram, GitHub, or YouTube.
      Focus on people with similar professional backgrounds, content styles, or interests.

      Return a JSON object with:
      1. originalProfile: { name: string, niche: string, description: string }
      2. suggestions: Array of { name: string, handle: string, platform: string, bio: string, relevanceScore: number (0-100), url: string, tags: string[] }

      Important: Ensure URLs are accurate. Use Google Search to verify.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              originalProfile: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  niche: { type: Type.STRING },
                  description: { type: Type.STRING },
                },
                required: ["name", "niche", "description"],
              },
              suggestions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    handle: { type: Type.STRING },
                    platform: { type: Type.STRING },
                    bio: { type: Type.STRING },
                    relevanceScore: { type: Type.NUMBER },
                    url: { type: Type.STRING },
                    tags: {
                      type: Type.ARRAY,
                      items: { type: Type.STRING },
                    },
                  },
                  required: ["name", "handle", "platform", "bio", "relevanceScore", "url", "tags"],
                },
              },
            },
            required: ["originalProfile", "suggestions"],
          },
        },
      });

      const data = JSON.parse(response.text || "{}");

      // Extract grounding sources
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const groundingSources = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri,
        }));

      return {
        ...data,
        groundingSources,
      };
    } catch (error) {
      console.error("Gemini Analysis Error:", error);
      throw new Error("Failed to analyze profile. Please ensure the URL is valid and public.");
    }
  }
}

import React from 'react';
import { SocialProfile } from '../types';
import { ExternalLink, User, Linkedin, Twitter, Github, Instagram, Youtube, Share2, Award } from 'lucide-react';

const PlatformIcon = ({ platform }: { platform: string }) => {
  const p = platform.toLowerCase();
  if (p.includes('linkedin')) return <Linkedin className="w-5 h-5 text-blue-400" />;
  if (p.includes('twitter') || p.includes('x')) return <Twitter className="w-5 h-5 text-gray-400" />;
  if (p.includes('github')) return <Github className="w-5 h-5 text-gray-300" />;
  if (p.includes('instagram')) return <Instagram className="w-5 h-5 text-pink-500" />;
  if (p.includes('youtube')) return <Youtube className="w-5 h-5 text-red-500" />;
  return <User className="w-5 h-5 text-purple-400" />;
};

interface ProfileCardProps {
  profile: SocialProfile;
}

const ProfileCard: React.FC<ProfileCardProps> = ({ profile }) => {
  return (
