const messages = [
  "Fetching profile metadata...",
  "Analyzing semantic niche...",
  "Querying global social graphs...",
  "Running relevance scoring...",
  "Verifying profile links...",
  "Polishing your matches...",
];

const LoadingState: React.FC = () => {
  const [msgIndex, setMsgIndex] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setMsgIndex((prev) => (prev + 1) % messages.length);
    }, 2500);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="flex flex-col items-center justify-center py-24 space-y-8">
      <div className="relative">
        <div className="absolute inset-0 bg-purple-500/20 blur-3xl rounded-full animate-pulse"></div>
        <div className="relative flex items-center justify-center w-24 h-24 glass rounded-full">
          <Search className="w-10 h-10 text-purple-400 animate-bounce" />
          <div className="absolute -top-1 -right-1">
            <Sparkles className="w-6 h-6 text-yellow-400 animate-spin" style={{ animationDuration: '3s' }} />
          </div>
        </div>
      </div>

      <div className="text-center">
        <h3 className="text-2xl font-bold mb-2">Finding your Digital Echoes</h3>
        <p className="text-gray-400 flex items-center justify-center gap-2">
          <Cpu className="w-4 h-4 animate-pulse" />
          {messages[msgIndex]}
        </p>
      </div>

      <div className="w-64 h-1.5 bg-white/5 rounded-full overflow-hidden">
        <div className="h-full bg-gradient-to-r from-purple-500 to-pink-500 animate-[loading_20s_ease-in-out_infinite]"></div>
      </div>

      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          100% { width: 100%; }
        }
      `}</style>
    </div>
  );
};

export default LoadingState;

