import { GoogleGenAI, Type } from "@google/genai";
import { ProfileAnalysis } from "../types";

export class GeminiService {
  // Fix: Initialize GoogleGenAI strictly using process.env.API_KEY as per guidelines
  private static ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  static async analyzeAndSearch(profileUrl: string): Promise<ProfileAnalysis> {
    const prompt = `
      Analyze this social media profile URL: ${profileUrl}.
      First, identify who this person/brand is and what their main niche or industry is.
      Then, search for 6 highly relevant similar profiles across platforms like X (formerly Twitter), LinkedIn, Instagram, GitHub, or YouTube.
      Focus on people with similar professional backgrounds, content styles, or interests.

      Return a JSON object with:
      1. originalProfile: { name: string, niche: string, description: string }
      2. suggestions: Array of { name: string, handle: string, platform: string, bio: string, relevanceScore: number (0-100), url: string, tags: string[] }

      Important: Ensure URLs are accurate. Use Google Search to verify.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              originalProfile: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  niche: { type: Type.STRING },
                  description: { type: Type.STRING },
                },
                required: ["name", "niche", "description"],
              },
              suggestions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    handle: { type: Type.STRING },
                    platform: { type: Type.STRING },
                    bio: { type: Type.STRING },
                    relevanceScore: { type: Type.NUMBER },
                    url: { type: Type.STRING },
                    tags: {
                      type: Type.ARRAY,
                      items: { type: Type.STRING },
                    },
                  },
                  required: ["name", "handle", "platform", "bio", "relevanceScore", "url", "tags"],
                },
              },
            },
            required: ["originalProfile", "suggestions"],
          },
        },
      });

      // Fix: robustly parse response.text which might contain non-JSON content when tools are used, as per guidelines
      const text = response.text || "{}";
      let data;
      try {
        data = JSON.parse(text);
      } catch (e) {
        // Fallback for cases where the model might return non-strict JSON format
        const jsonMatch = text.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          data = JSON.parse(jsonMatch[0]);
        } else {
          throw new Error("Could not parse AI response as JSON");
        }
      }

      // Extract grounding sources from the response candidates as per guidelines
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const groundingSources = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri,
        }));

      return {
        ...data,
        groundingSources,
      };
    } catch (error) {
      console.error("Gemini Analysis Error:", error);
      throw new Error("Failed to analyze profile. Please ensure the URL is valid and public.");
    }
  }
}

