import { GoogleGenAI, Type } from "@google/genai";
import { ProfileAnalysis } from "../types";

export class GeminiService {
  // Initialize GoogleGenAI strictly using process.env.API_KEY as per guidelines
  private static ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  static async analyzeAndSearch(profileUrl: string): Promise<ProfileAnalysis> {
    const prompt = `
      Analyze this social media profile URL: ${profileUrl}.

      Step 1: Identify who this person/brand is and their core niche.
      Step 2: Determine 3-4 COMPLEMENTARY niches that would make great collaborators, partners, or service providers.
      Step 3: Use Google Search to find 6 REAL, ACTIVE social media profiles in these complementary niches.

      CRITICAL URL VERIFICATION RULES:
      - ONLY include profiles where you can verify the EXACT URL exists.
      - DO NOT hallucinate or guess URLs by appending handles to platform domains (e.g., do not just guess twitter.com/handle).
      - PREFER profiles found directly in search results with confirmed active presence.
      - If a suggested partner's URL cannot be verified as 100% accurate and working, DISCARD that suggestion and find another.
      - Ensure the URL leads directly to the user's profile page, not a generic search page.

      Return a JSON object with:
      1. originalProfile: { name: string, niche: string, description: string }
      2. suggestions: Array of { 
          name: string, 
          handle: string, 
          platform: string, 
          bio: string, 
          relevanceScore: number (0-100), 
          url: string, 
          tags: string[] 
      }
    `;

    try {
      // Use the gemini-3-pro-preview model for more complex reasoning and better tool utilization
      const response = await this.ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              originalProfile: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  niche: { type: Type.STRING },
                  description: { type: Type.STRING },
                },
                required: ["name", "niche", "description"],
              },
              suggestions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    handle: { type: Type.STRING },
                    platform: { type: Type.STRING },
                    bio: { type: Type.STRING },
                    relevanceScore: { type: Type.NUMBER },
                    url: { type: Type.STRING },
                    tags: {
                      type: Type.ARRAY,
                      items: { type: Type.STRING },
                    },
                  },
                  required: ["name", "handle", "platform", "bio", "relevanceScore", "url", "tags"],
                },
              },
            },
            required: ["originalProfile", "suggestions"],
          },
        },
      });

      const text = response.text || "{}";
      let data;
      try {
        data = JSON.parse(text);
      } catch (e) {
        const jsonMatch = text.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          data = JSON.parse(jsonMatch[0]);
        } else {
          throw new Error("Could not parse AI response as JSON");
        }
      }

      // Extract grounding sources to verify transparency
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const groundingSources = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web.title,
          uri: chunk.web.uri,
        }));

      // Double-check: Filter out any items that don't have a protocol (sanity check for AI output)
      if (data.suggestions) {
        data.suggestions = data.suggestions.filter((s: any) => 
          s.url && (s.url.startsWith('http://') || s.url.startsWith('https://'))
        );
      }

      return {
        ...data,
        groundingSources,
      };
    } catch (error) {
      console.error("Gemini Analysis Error:", error);
      throw new Error("Failed to verify social synergy. Please check the source URL and try again.");
    }
  }
}

